-- Migration 0040: ML mod features from GGPK data
-- Adds mod base name mapping and per-item mod features tables
-- 2026-03-17

-- 1. Mod base name mapping table (from GGPK)
CREATE TABLE IF NOT EXISTS poe_trade.ml_mod_base_name_map_v1 (
    mod_text_pattern String,
    mod_base_name String,
    mod_tier UInt8,
    mod_max_tier UInt8,
    mod_max_value Float64,
    mod_generation_type LowCardinality(String),
    required_level UInt16,
    updated_at DateTime64(3, 'UTC')
) ENGINE = ReplacingMergeTree(updated_at)
ORDER BY (mod_base_name, mod_tier)
SETTINGS index_granularity = 8192;

-- 2. Per-item mod features table (JSON sparse format)
CREATE TABLE IF NOT EXISTS poe_trade.ml_item_mod_features_v1 (
    league LowCardinality(String),
    item_id String,
    mod_features_json String,
    mod_count UInt8,
    as_of_ts DateTime64(3, 'UTC'),
    updated_at DateTime64(3, 'UTC')
) ENGINE = ReplacingMergeTree(updated_at)
ORDER BY (league, item_id)
SETTINGS index_granularity = 8192;

